import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, 
  FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, 
  FaClock, FaStar, FaSpinner, FaUser, FaSearch,
  FaFilter, FaFileWord, FaFilePowerpoint, FaFileImage,
  FaFileArchive, FaPrint, FaHeart, FaShareAlt, FaBookmark,
  FaChevronRight, FaTimes, FaCheck, FaExclamationTriangle,
  FaRegHeart, FaRegBookmark, FaSortAmountDown, FaSortAmountUp
} from 'react-icons/fa';
import { BeatLoader, ClipLoader } from 'react-spinners';
import styles from './MaterialsPage.module.css';
import PreviewModal from '../PreviewModal/PreviewModal';
import FileTypeBadge from '../FileTypeBadge/FileTypeBadge';
import { materialsService } from '../../services/materialsService';
import { showNotification, showToast } from '../../utils/notifications';
import { formatFileSize, isPreviewable } from '../../utils/fileUtils';
import { MATERIAL_TYPES, MATERIAL_TYPE_MAP } from '../../constants/materialTypes';
import { getFileIcon } from '../../constants/fileIcons';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';
const USE_MOCK_DATA = process.env.REACT_APP_USE_MOCK_DATA === 'true';

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  
  // State Management
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [courseInfo, setCourseInfo] = useState(null);
  const [previewMaterial, setPreviewMaterial] = useState(null);
  const [favorites, setFavorites] = useState(new Set());
  const [bookmarks, setBookmarks] = useState(new Set());
  const [sortBy, setSortBy] = useState('date'); // date, name, downloads, rating
  const [sortOrder, setSortOrder] = useState('desc'); // asc, desc
  const [stats, setStats] = useState({
    total: 0,
    byType: {},
    totalDownloads: 0,
    totalViews: 0
  });
  const [pageInfo, setPageInfo] = useState({
    currentPage: 1,
    totalPages: 1,
    hasMore: false
  });
  const [selectedMaterials, setSelectedMaterials] = useState(new Set());
  const [bulkAction, setBulkAction] = useState(null);
  
  // Memoized values
  const materialTypes = useMemo(() => MATERIAL_TYPES, []);
  const filteredMaterials = useMemo(() => {
    let filtered = materials.filter(material => {
      const matchesType = selectedType === 'all' || material.type === selectedType;
      const matchesSearch = searchQuery === '' ||
        material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        material.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
        material.tags?.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesType && matchesSearch;
    });
    
    // Sorting
    filtered.sort((a, b) => {
      let aValue, bValue;
      
      switch (sortBy) {
        case 'name':
          aValue = a.title.toLowerCase();
          bValue = b.title.toLowerCase();
          break;
        case 'downloads':
          aValue = a.downloads || 0;
          bValue = b.downloads || 0;
          break;
        case 'rating':
          aValue = a.rating || 0;
          bValue = b.rating || 0;
          break;
        case 'date':
        default:
          aValue = new Date(a.uploadDate || a.createdAt);
          bValue = new Date(b.uploadDate || b.createdAt);
      }
      
      if (sortOrder === 'asc') {
        return aValue > bValue ? 1 : -1;
      } else {
        return aValue < bValue ? 1 : -1;
      }
    });
    
    return filtered;
  }, [materials, selectedType, searchQuery, sortBy, sortOrder]);
  
  // Fetch data from backend
  const fetchMaterials = useCallback(async () => {
    setLoading(true);
    setError(null);
    
    try {
      let response;
      
      if (USE_MOCK_DATA) {
        // Mock data for development
        await new Promise(resolve => setTimeout(resolve, 1000));
        response = {
          success: true,
          subject: generateMockSubject(),
          materials: generateMockMaterials(),
          stats: {
            total: 6,
            byType: { syllabus: 1, notes: 1, pyq: 1, important: 1, lab: 1, assignment: 1 },
            totalDownloads: 1250,
            totalViews: 3500
          }
        };
      } else {
        // Real API call
        response = await materialsService.getSubjectMaterials(subjectId);
      }
      
      if (response.success) {
        setSubject(response.subject);
        setMaterials(response.materials || []);
        setStats(response.stats || { total: 0, byType: {} });
        
        // Fetch course info if available
        if (response.subject?.course_id) {
          try {
            const courseResponse = await materialsService.getCourse(response.subject.course_id);
            if (courseResponse.success) {
              setCourseInfo(courseResponse.course);
            }
          } catch (err) {
            console.warn('Failed to fetch course info:', err);
          }
        }
        
        // Load user preferences from localStorage
        const savedFavorites = JSON.parse(localStorage.getItem(`favorites_${subjectId}`) || '[]');
        const savedBookmarks = JSON.parse(localStorage.getItem(`bookmarks_${subjectId}`) || '[]');
        setFavorites(new Set(savedFavorites));
        setBookmarks(new Set(savedBookmarks));
        
        showToast('Materials loaded successfully', 'success');
      } else {
        throw new Error(response.error || 'Failed to load materials');
      }
    } catch (error) {
      console.error('Error fetching materials:', error);
      setError(error.message);
      showToast('Failed to load materials', 'error');
      
      // Fallback to mock data
      setSubject(generateMockSubject());
      setMaterials(generateMockMaterials());
    } finally {
      setLoading(false);
    }
  }, [subjectId]);
  
  // Initial data fetch
  useEffect(() => {
    fetchMaterials();
  }, [fetchMaterials]);
  
  // Handle material download
  const handleDownload = async (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    try {
      let fileBlob;
      let fileName = `${material.title.replace(/[^a-zA-Z0-9]/g, '_')}.${material.fileType || 'pdf'}`;
      
      if (USE_MOCK_DATA || !material.fileUrl) {
        // Generate mock file
        const fileContent = `STUDY PORTAL - ${material.title}\n\n` +
          `Subject: ${subject?.name || 'Unknown'}\n` +
          `Description: ${material.description}\n` +
          `File Type: ${material.fileType?.toUpperCase() || 'PDF'}\n` +
          `Uploaded: ${material.uploadDate}\n` +
          `Uploaded by: ${material.user}\n\n` +
          `--- CONTENT ---\n\n` +
          `This is a sample content for ${material.title}.\n` +
          `In the real application, this would be the actual study material.\n\n` +
          `Downloaded on: ${new Date().toLocaleDateString()}\n` +
          `© Study Portal ${new Date().getFullYear()}`;
        
        fileBlob = new Blob([fileContent], { type: 'text/plain' });
      } else {
        // Download from server
        const response = await materialsService.downloadMaterial(material.id);
        fileBlob = response.data;
        
        // Extract filename from response headers
        const contentDisposition = response.headers['content-disposition'];
        if (contentDisposition) {
          const filenameMatch = contentDisposition.match(/filename="?(.+?)"?$/);
          if (filenameMatch) fileName = filenameMatch[1];
        }
      }
      
      // Create download link
      const url = window.URL.createObjectURL(fileBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = fileName;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      
      // Update download count locally
      setMaterials(prev => prev.map(m => 
        m.id === material.id 
          ? { ...m, downloads: (m.downloads || 0) + 1 }
          : m
      ));
      
      // Update stats
      setStats(prev => ({
        ...prev,
        totalDownloads: prev.totalDownloads + 1
      }));
      
      // Track analytics
      await materialsService.trackDownload(material.id);
      
      showNotification(
        'Download Complete!', 
        `"${material.title}" has been downloaded`, 
        'success'
      );
    } catch (error) {
      console.error('Download error:', error);
      showNotification(
        'Download Failed', 
        error.message || 'Please try again later',
        'error'
      );
    } finally {
      setDownloading(prev => ({ ...prev, [material.id]: false }));
    }
  };
  
  // Handle material preview
  const handlePreview = (material) => {
    if (isPreviewable(material.fileType || 'pdf')) {
      setPreviewMaterial(material);
    } else {
      showToast('Preview not available for this file type', 'warning');
    }
  };
  
  // Handle favorite toggle
  const handleFavorite = (materialId) => {
    const newFavorites = new Set(favorites);
    if (newFavorites.has(materialId)) {
      newFavorites.delete(materialId);
      showToast('Removed from favorites', 'info');
    } else {
      newFavorites.add(materialId);
      showToast('Added to favorites', 'success');
    }
    setFavorites(newFavorites);
    localStorage.setItem(`favorites_${subjectId}`, JSON.stringify([...newFavorites]));
  };
  
  // Handle bookmark toggle
  const handleBookmark = (materialId) => {
    const newBookmarks = new Set(bookmarks);
    if (newBookmarks.has(materialId)) {
      newBookmarks.delete(materialId);
      showToast('Removed from bookmarks', 'info');
    } else {
      newBookmarks.add(materialId);
      showToast('Added to bookmarks', 'success');
    }
    setBookmarks(newBookmarks);
    localStorage.setItem(`bookmarks_${subjectId}`, JSON.stringify([...newBookmarks]));
  };
  
  // Handle material selection for bulk actions
  const handleSelectMaterial = (materialId) => {
    const newSelection = new Set(selectedMaterials);
    if (newSelection.has(materialId)) {
      newSelection.delete(materialId);
    } else {
      newSelection.add(materialId);
    }
    setSelectedMaterials(newSelection);
  };
  
  // Handle select all
  const handleSelectAll = () => {
    if (selectedMaterials.size === filteredMaterials.length) {
      setSelectedMaterials(new Set());
    } else {
      setSelectedMaterials(new Set(filteredMaterials.map(m => m.id)));
    }
  };
  
  // Handle bulk download
  const handleBulkDownload = async () => {
    if (selectedMaterials.size === 0) {
      showToast('No materials selected', 'warning');
      return;
    }
    
    try {
      showNotification('Preparing Download', `Downloading ${selectedMaterials.size} files...`, 'info');
      
      for (const materialId of selectedMaterials) {
        const material = materials.find(m => m.id === materialId);
        if (material) {
          await handleDownload(material);
          await new Promise(resolve => setTimeout(resolve, 500)); // Delay between downloads
        }
      }
      
      setSelectedMaterials(new Set());
      showNotification(
        'Bulk Download Complete!',
        `${selectedMaterials.size} files downloaded successfully`,
        'success'
      );
    } catch (error) {
      showToast('Bulk download failed', 'error');
    }
  };
  
  // Handle share material
  const handleShare = async (material) => {
    const shareUrl = `${window.location.origin}/share/material/${material.id}`;
    const shareText = `Check out this study material: ${material.title}`;
    
    if (navigator.share) {
      try {
        await navigator.share({
          title: material.title,
          text: shareText,
          url: shareUrl,
        });
      } catch (error) {
        console.log('Share cancelled:', error);
      }
    } else {
      // Fallback to clipboard
      navigator.clipboard.writeText(`${shareText}\n${shareUrl}`)
        .then(() => showToast('Link copied to clipboard', 'success'))
        .catch(() => showToast('Failed to copy link', 'error'));
    }
  };
  
  // Generate mock data (for development)
  const generateMockSubject = () => ({
    id: subjectId,
    name: 'Data Structures',
    code: 'CSE301',
    credits: 4,
    type: 'Theory',
    materials: 6,
    description: 'Introduction to data structures and algorithms',
    professor: 'Dr. Smith',
    department: 'Computer Science',
    semester: 3
  });
  
  const generateMockMaterials = () => {
    const mockData = [
      {
        id: 1,
        title: 'Data Structures Complete Syllabus',
        type: 'syllabus',
        description: 'Official syllabus with unit-wise distribution and marking scheme',
        fileSize: '1.2 MB',
        pages: 12,
        uploadDate: '15 Jan 2024',
        downloads: 245,
        views: 560,
        rating: 4.5,
        fileType: 'pdf',
        user: 'Admin',
        tags: ['official', 'syllabus', 'academic'],
        isNew: true,
        isVerified: true,
        uploadedBy: { name: 'Admin', avatar: '👨‍💼' }
      },
      {
        id: 2,
        title: 'Data Structures Complete Notes',
        type: 'notes',
        description: 'Comprehensive notes covering all topics with examples and diagrams',
        fileSize: '4.5 MB',
        pages: 45,
        uploadDate: '20 Jan 2024',
        downloads: 520,
        views: 1200,
        rating: 4.8,
        fileType: 'pdf',
        user: 'Professor',
        tags: ['comprehensive', 'notes', 'examples'],
        isNew: true,
        isVerified: true,
        uploadedBy: { name: 'Prof. Johnson', avatar: '👨‍🏫' }
      },
      {
        id: 3,
        title: 'Data Structures PYQ 2020-2023',
        type: 'pyq',
        description: 'Previous year question papers with solutions and explanations',
        fileSize: '3.2 MB',
        pages: 35,
        uploadDate: '05 Jan 2024',
        downloads: 890,
        views: 2100,
        rating: 4.7,
        fileType: 'pdf',
        user: 'Exam Cell',
        tags: ['pyq', 'exam', 'solutions'],
        isVerified: true,
        uploadedBy: { name: 'Exam Cell', avatar: '📊' }
      },
      {
        id: 4,
        title: 'Data Structures Important Questions',
        type: 'important',
        description: 'Most expected questions and important topics for exams',
        fileSize: '1.5 MB',
        pages: 18,
        uploadDate: '22 Jan 2024',
        downloads: 320,
        views: 780,
        rating: 4.6,
        fileType: 'pdf',
        user: 'Faculty',
        tags: ['important', 'exam', 'questions'],
        uploadedBy: { name: 'Dr. Williams', avatar: '👩‍🏫' }
      },
      {
        id: 5,
        title: 'Data Structures Lab Manual',
        type: 'lab',
        description: 'Complete lab manual with experiments, procedures, and viva questions',
        fileSize: '2.8 MB',
        pages: 32,
        uploadDate: '18 Jan 2024',
        downloads: 210,
        views: 450,
        rating: 4.4,
        fileType: 'pdf',
        user: 'Lab Incharge',
        tags: ['lab', 'practical', 'experiments'],
        uploadedBy: { name: 'Lab Assistant', avatar: '🔬' }
      },
      {
        id: 6,
        title: 'Data Structures Assignments',
        type: 'assignment',
        description: 'Solved assignments and practice problems',
        fileSize: '2.1 MB',
        pages: 25,
        uploadDate: '25 Jan 2024',
        downloads: 180,
        views: 420,
        rating: 4.3,
        fileType: 'doc',
        user: 'Teaching Assistant',
        tags: ['assignments', 'practice', 'problems'],
        uploadedBy: { name: 'TA Alex', avatar: '👨‍🎓' }
      }
    ];
    
    return mockData;
  };
  
  // Calculate material stats
  const calculateStats = useMemo(() => {
    const stats = {
      total: materials.length,
      byType: {},
      totalDownloads: materials.reduce((sum, m) => sum + (m.downloads || 0), 0),
      totalViews: materials.reduce((sum, m) => sum + (m.views || 0), 0),
      totalPages: materials.reduce((sum, m) => sum + (m.pages || 0), 0),
      avgRating: materials.length > 0 
        ? (materials.reduce((sum, m) => sum + (m.rating || 0), 0) / materials.length).toFixed(1)
        : 0
    };
    
    materials.forEach(material => {
      stats.byType[material.type] = (stats.byType[material.type] || 0) + 1;
    });
    
    return stats;
  }, [materials]);
  
  // Render loading state
  if (loading) {
    return (
      <div className={styles.container}>
        <div className={styles.innerContainer}>
          <button className={styles.backButton} onClick={() => navigate(-1)}>
            <FaArrowLeft /> Back
          </button>
          <div className={styles.loadingContainer}>
            <ClipLoader size={60} color="#4f46e5" />
            <h3>Loading Materials...</h3>
            <p>Fetching study materials from the server</p>
          </div>
        </div>
      </div>
    );
  }
  
  // Render error state
  if (error && materials.length === 0) {
    return (
      <div className={styles.container}>
        <div className={styles.innerContainer}>
          <button className={styles.backButton} onClick={() => navigate(-1)}>
            <FaArrowLeft /> Back
          </button>
          <div className={styles.errorContainer}>
            <FaExclamationTriangle className={styles.errorIcon} />
            <h3>Failed to Load Materials</h3>
            <p>{error}</p>
            <div className={styles.errorActions}>
              <button 
                className={styles.retryButton}
                onClick={fetchMaterials}
              >
                <FaSpinner className={styles.spin} /> Retry
              </button>
              <button 
                className={styles.secondaryButton}
                onClick={() => navigate(`/course/${courseId}/year/${yearId}/sem/${semId}`)}
              >
                Back to Subjects
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }
  
  return (
    <div className={styles.container}>
      {/* Preview Modal */}
      {previewMaterial && (
        <PreviewModal
          material={previewMaterial}
          onClose={() => setPreviewMaterial(null)}
          onDownload={handleDownload}
        />
      )}
      
      <div className={styles.innerContainer}>
        {/* Header with Back Button */}
        <div className={styles.header}>
          <button className={styles.backButton} onClick={() => navigate(-1)}>
            <FaArrowLeft /> Back to Subjects
          </button>
          
          {selectedMaterials.size > 0 && (
            <div className={styles.bulkActions}>
              <span className={styles.selectedCount}>
                {selectedMaterials.size} selected
              </span>
              <button 
                className={styles.bulkDownloadButton}
                onClick={handleBulkDownload}
                disabled={Object.keys(downloading).some(id => selectedMaterials.has(Number(id)))}
              >
                <FaDownload /> Download Selected
              </button>
              <button 
                className={styles.clearSelectionButton}
                onClick={() => setSelectedMaterials(new Set())}
              >
                <FaTimes /> Clear
              </button>
            </div>
          )}
        </div>
        
        {/* Subject Header */}
        <div className={styles.subjectHeader}>
          <div className={styles.subjectIconContainer}>
            <div className={styles.subjectIcon}>📚</div>
          </div>
          
          <div className={styles.subjectInfo}>
            <div className={styles.subjectHeaderTop}>
              <div>
                <h1 className={styles.subjectName}>{subject?.name || 'Subject'}</h1>
                <div className={styles.subjectMeta}>
                  <span className={styles.subjectCode}>
                    Code: <strong>{subject?.code || 'N/A'}</strong>
                  </span>
                  <span className={styles.subjectCredits}>
                    <FaStar /> <strong>{subject?.credits || 0} Credits</strong>
                  </span>
                  <span className={styles.subjectType}>
                    🏷️ <strong>{subject?.type || 'Theory'}</strong>
                  </span>
                  {subject?.professor && (
                    <span className={styles.subjectProfessor}>
                      👨‍🏫 <strong>{subject.professor}</strong>
                    </span>
                  )}
                </div>
                
                <div className={styles.breadcrumb}>
                  <span className={styles.breadcrumbItem}>
                    {courseInfo?.name || `Course ${courseId}`}
                  </span>
                  <FaChevronRight className={styles.breadcrumbArrow} />
                  <span className={styles.breadcrumbItem}>
                    Year {yearId}
                  </span>
                  <FaChevronRight className={styles.breadcrumbArrow} />
                  <span className={styles.breadcrumbItem}>
                    Semester {semId}
                  </span>
                  <FaChevronRight className={styles.breadcrumbArrow} />
                  <span className={`${styles.breadcrumbItem} ${styles.currentBreadcrumb}`}>
                    {subject?.name || 'Subject'}
                  </span>
                </div>
              </div>
              
              <div className={styles.statsContainer}>
                <div className={styles.statBox}>
                  <div className={styles.statNumber}>{calculateStats.total}</div>
                  <div className={styles.statLabel}>Total Files</div>
                </div>
                <div className={styles.statBox}>
                  <div className={styles.statNumber}>{calculateStats.totalDownloads}</div>
                  <div className={styles.statLabel}>Downloads</div>
                </div>
                <div className={styles.statBox}>
                  <div className={styles.statNumber}>{calculateStats.avgRating}</div>
                  <div className={styles.statLabel}>Avg Rating</div>
                </div>
              </div>
            </div>
            
            {subject?.description && (
              <div className={styles.subjectDescription}>
                {subject.description}
              </div>
            )}
          </div>
        </div>
        
        {/* Search and Filter Bar */}
        <div className={styles.searchFilterBar}>
          <div className={styles.searchContainer}>
            <FaSearch className={styles.searchIcon} />
            <input
              type="text"
              className={styles.searchInput}
              placeholder={`Search ${subject?.name || 'subject'} materials...`}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            {searchQuery && (
              <button 
                className={styles.clearSearchButton}
                onClick={() => setSearchQuery('')}
              >
                <FaTimes />
              </button>
            )}
          </div>
          
          <div className={styles.filterControls}>
            <div className={styles.sortControls}>
              <label className={styles.sortLabel}>
                <FaSortAmountDown /> Sort by:
              </label>
              <select 
                className={styles.sortSelect}
                value={sortBy}
                onChange={(e) => setSortBy(e.target.value)}
              >
                <option value="date">Upload Date</option>
                <option value="name">Name</option>
                <option value="downloads">Downloads</option>
                <option value="rating">Rating</option>
              </select>
              <button 
                className={styles.sortOrderButton}
                onClick={() => setSortOrder(prev => prev === 'asc' ? 'desc' : 'asc')}
              >
                {sortOrder === 'asc' ? <FaSortAmountUp /> : <FaSortAmountDown />}
              </button>
            </div>
          </div>
        </div>
        
        {/* Material Type Filters */}
        <div className={styles.typeFilterContainer}>
          <h3 className={styles.filterTitle}>
            Filter by Material Type
          </h3>
          <div className={styles.typeFilters}>
            {materialTypes.map((type) => (
              <button
                key={type.id}
                className={`${styles.typeFilterButton} ${
                  selectedType === type.id ? styles.typeFilterButtonActive : ''
                }`}
                onClick={() => setSelectedType(type.id)}
                style={{
                  '--type-color': type.color,
                  '--type-bg': `${type.color}15`
                }}
              >
                <span className={styles.typeIcon}>{type.icon}</span>
                <span className={styles.typeName}>{type.name}</span>
                {type.id !== 'all' && (
                  <span className={styles.typeCount}>
                    {calculateStats.byType[type.id] || 0}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>
        
        {/* Materials Grid */}
        {filteredMaterials.length === 0 ? (
          <div className={styles.emptyState}>
            <div className={styles.emptyIcon}>📭</div>
            <h3 className={styles.emptyTitle}>No materials found</h3>
            <p className={styles.emptyMessage}>
              {searchQuery 
                ? `No materials match "${searchQuery}"`
                : 'No materials available for this subject'
              }
            </p>
            {searchQuery && (
              <button
                className={styles.emptyActionButton}
                onClick={() => setSearchQuery('')}
              >
                Clear Search
              </button>
            )}
          </div>
        ) : (
          <>
            {/* Materials Header */}
            <div className={styles.materialsHeader}>
              <div className={styles.materialsTitle}>
                <h3>
                  {selectedType === 'all' 
                    ? 'All Study Materials' 
                    : MATERIAL_TYPE_MAP[selectedType]?.name
                  }
                  <span className={styles.materialsCount}>
                    ({filteredMaterials.length})
                  </span>
                </h3>
                <div className={styles.selectAllContainer}>
                  <input
                    type="checkbox"
                    id="selectAll"
                    checked={selectedMaterials.size === filteredMaterials.length}
                    onChange={handleSelectAll}
                    className={styles.selectAllCheckbox}
                  />
                  <label htmlFor="selectAll" className={styles.selectAllLabel}>
                    Select All
                  </label>
                </div>
              </div>
              
              <div className={styles.materialsStats}>
                <span className={styles.materialsStat}>
                  <FaDownload /> {calculateStats.totalDownloads} downloads
                </span>
                <span className={styles.materialsStat}>
                  <FaEye /> {calculateStats.totalViews} views
                </span>
                <span className={styles.materialsStat}>
                  📖 {calculateStats.totalPages} total pages
                </span>
              </div>
            </div>
            
            {/* Materials Grid */}
            <div className={styles.materialsGrid}>
              {filteredMaterials.map((material) => {
                const typeInfo = MATERIAL_TYPE_MAP[material.type];
                const fileIcon = getFileIcon(material.fileType);
                const isFavorite = favorites.has(material.id);
                const isBookmarked = bookmarks.has(material.id);
                const isSelected = selectedMaterials.has(material.id);
                
                return (
                  <div
                    key={material.id}
                    className={`${styles.materialCard} ${
                      isSelected ? styles.materialCardSelected : ''
                    }`}
                    onClick={(e) => {
                      if (e.target.type !== 'checkbox') {
                        handleSelectMaterial(material.id);
                      }
                    }}
                  >
                    {/* Selection Checkbox */}
                    <div className={styles.materialSelection}>
                      <input
                        type="checkbox"
                        checked={isSelected}
                        onChange={() => handleSelectMaterial(material.id)}
                        className={styles.materialCheckbox}
                        onClick={(e) => e.stopPropagation()}
                      />
                    </div>
                    
                    {/* Card Header */}
                    <div 
                      className={styles.materialHeader}
                      style={{
                        backgroundColor: `${typeInfo?.color}10`
                      }}
                    >
                      <div className={styles.materialType}>
                        <span className={styles.typeIcon} style={{ color: typeInfo?.color }}>
                          {typeInfo?.icon}
                        </span>
                        <span className={styles.typeName} style={{ color: typeInfo?.color }}>
                          {typeInfo?.name}
                        </span>
                      </div>
                      
                      <div className={styles.materialBadges}>
                        {material.isNew && (
                          <span className={styles.newBadge}>NEW</span>
                        )}
                        {material.isVerified && (
                          <span className={styles.verifiedBadge}>
                            <FaCheck /> Verified
                          </span>
                        )}
                        <FileTypeBadge fileType={material.fileType} />
                      </div>
                    </div>
                    
                    {/* Card Content */}
                    <div className={styles.materialContent}>
                      <h4 className={styles.materialTitle}>
                        {material.title}
                      </h4>
                      
                      <p className={styles.materialDescription}>
                        {material.description}
                      </p>
                      
                      {/* Tags */}
                      {material.tags && material.tags.length > 0 && (
                        <div className={styles.materialTags}>
                          {material.tags.slice(0, 3).map((tag, index) => (
                            <span key={index} className={styles.materialTag}>
                              #{tag}
                            </span>
                          ))}
                          {material.tags.length > 3 && (
                            <span className={styles.moreTags}>
                              +{material.tags.length - 3} more
                            </span>
                          )}
                        </div>
                      )}
                      
                      {/* Stats */}
                      <div className={styles.materialStats}>
                        <div className={styles.materialStat}>
                          <FaClock className={styles.statIcon} />
                          <span>{material.uploadDate}</span>
                        </div>
                        <div className={styles.materialStat}>
                          <FaDownload className={styles.statIcon} />
                          <span>{material.downloads || 0} downloads</span>
                        </div>
                        <div className={styles.materialStat}>
                          <FaEye className={styles.statIcon} />
                          <span>{material.views || 0} views</span>
                        </div>
                        <div className={styles.materialStat}>
                          <FaStar className={styles.statIcon} style={{ color: '#fbbf24' }} />
                          <span>{material.rating || 0}/5</span>
                        </div>
                      </div>
                      
                      {/* File Info */}
                      <div className={styles.materialFileInfo}>
                        <div className={styles.fileType}>
                          <span className={styles.fileIcon}>
                            {fileIcon.icon}
                          </span>
                          <span>{material.fileSize}</span>
                        </div>
                        <div className={styles.filePages}>
                          <span className={styles.pagesIcon}>📖</span>
                          <span>{material.pages || 0} pages</span>
                        </div>
                        <div className={styles.uploadedBy}>
                          <span className={styles.userAvatar}>
                            {material.uploadedBy?.avatar || '👤'}
                          </span>
                          <span>{material.uploadedBy?.name || material.user}</span>
                        </div>
                      </div>
                    </div>
                    
                    {/* Action Buttons */}
                    <div className={styles.materialActions}>
                      {/* Left Actions - Favorites & Bookmarks */}
                      <div className={styles.materialLeftActions}>
                        <button
                          className={`${styles.actionButton} ${styles.favoriteButton} ${
                            isFavorite ? styles.favoriteButtonActive : ''
                          }`}
                          onClick={(e) => {
                            e.stopPropagation();
                            handleFavorite(material.id);
                          }}
                          title={isFavorite ? 'Remove from favorites' : 'Add to favorites'}
                        >
                          {isFavorite ? <FaHeart /> : <FaRegHeart />}
                        </button>
                        
                        <button
                          className={`${styles.actionButton} ${styles.bookmarkButton} ${
                            isBookmarked ? styles.bookmarkButtonActive : ''
                          }`}
                          onClick={(e) => {
                            e.stopPropagation();
                            handleBookmark(material.id);
                          }}
                          title={isBookmarked ? 'Remove bookmark' : 'Bookmark'}
                        >
                          {isBookmarked ? <FaBookmark /> : <FaRegBookmark />}
                        </button>
                        
                        <button
                          className={`${styles.actionButton} ${styles.shareButton}`}
                          onClick={(e) => {
                            e.stopPropagation();
                            handleShare(material);
                          }}
                          title="Share"
                        >
                          <FaShareAlt />
                        </button>
                      </div>
                      
                      {/* Right Actions - Preview & Download */}
                      <div className={styles.materialRightActions}>
                        <button
                          className={`${styles.actionButton} ${styles.previewButton}`}
                          onClick={(e) => {
                            e.stopPropagation();
                            handlePreview(material);
                          }}
                          disabled={!isPreviewable(material.fileType || 'pdf')}
                          title={isPreviewable(material.fileType || 'pdf') ? 'Preview' : 'Preview not available'}
                        >
                          <FaEye />
                          <span>Preview</span>
                        </button>
                        
                        <button
                          className={`${styles.actionButton} ${styles.downloadButton}`}
                          onClick={(e) => {
                            e.stopPropagation();
                            handleDownload(material);
                          }}
                          disabled={downloading[material.id]}
                        >
                          {downloading[material.id] ? (
                            <>
                              <FaSpinner className={styles.spin} />
                              <span>Downloading...</span>
                            </>
                          ) : (
                            <>
                              <FaDownload />
                              <span>Download</span>
                            </>
                          )}
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </>
        )}
        
        {/* Development Mode Indicator */}
        {USE_MOCK_DATA && (
          <div className={styles.devModeBanner}>
            <FaExclamationTriangle />
            <span>Development Mode: Using mock data</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default MaterialsPage;
